'use client';

import { useState, useEffect } from 'react';
import { calculateTax, formatPKR, TaxInput, TaxResult } from '../lib/taxEngine';
import type { TaxpayerType, TaxYear } from '../lib/slabs';

const initialInput: TaxInput = {
  taxpayerType: 'salaried',
  taxYear: '2025',
  filerStatus: 'filer',
  isOverseas: false,
  salary: 1200000,
  businessRevenue: 0,
  businessExpenses: 0,
  rentalIncome: 0,
  freelanceIncome: 0,
  capitalGains: 0,
  otherIncome: 0,
  zakat: 0,
  pensionContribution: 0,
  lifeInsurance: 0,
  donations: 0,
  whtSalary: 30000,
  whtBank: 0,
  whtMobile: 0,
  whtProperty: 0,
  whtOther: 0,
};

export default function TaxCalculator() {
  const [input, setInput] = useState<TaxInput>(initialInput);
  const [result, setResult] = useState<TaxResult | null>(null);

  useEffect(() => {
    const res = calculateTax(input);
    setResult(res);
  }, [input]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    
    let parsedValue: string | number | boolean;
    if (type === 'checkbox') {
      parsedValue = (e.target as HTMLInputElement).checked;
    } else if (type === 'number') {
      parsedValue = parseFloat(value) || 0;
    } else {
      parsedValue = value;
    }

    setInput(prev => ({
      ...prev,
      [name]: parsedValue,
    }));
  };
  
  const renderResult = () => {
    if (!result) return null;
    return (
      <div style={{ background: '#f0f8ff', padding: '20px', borderRadius: '8px' }}>
        <h3>Tax Summary (2024-2025)</h3>
        <p><strong>Total Income:</strong> {formatPKR(result.totalIncome)}</p>
        <p><strong>Taxable Income:</strong> {formatPKR(result.taxableIncome)}</p>
        <p><strong>Gross Tax (on Slab {result.currentSlab}):</strong> {formatPKR(result.grossTax)}</p>
        <p><strong>Total Credits (Donations, Pension):</strong> {formatPKR(result.totalCredits)}</p>
        <hr />
        <p><strong>Tax After Credits:</strong> {formatPKR(result.taxAfterCredits)}</p>
        <p><strong>Withholding Tax Already Paid:</strong> {formatPKR(result.totalWHTPaid)}</p>
        <div style={{marginTop: '10px', paddingTop: '10px', borderTop: '1px solid #ccc'}}>
          <h4 style={{ color: result.isRefund ? 'green' : 'red' }}>
            {result.isRefund ? 'Refund Due From FBR:' : 'Net Tax Payable to FBR:'}
          </h4>
          <p style={{ fontSize: '1.5rem', fontWeight: 'bold', color: result.isRefund ? 'green' : 'red' }}>
            {formatPKR(result.netPayable)}
          </p>
        </div>
        {result.nonfilerPenalty && <p style={{color: 'orange'}}>{result.nonfilerPenalty}</p>}
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', gap: '2rem', maxWidth: '1200px', margin: 'auto', padding: '20px' }}>
      <div style={{ flex: 1 }}>
        <h2>Tax Calculator Pakistan</h2>
        <div>
          <label>Tax Year</label>
          <select name="taxYear" value={input.taxYear} onChange={handleInputChange}>
            <option value="2025">2025 (July 2024 - June 2025)</option>
            <option value="2024">2024 (July 2023 - June 2024)</option>
          </select>
        </div>
        <div>
          <label>Filer Status</label>
          <select name="filerStatus" value={input.filerStatus} onChange={handleInputChange}>
            <option value="filer">Filer</option>
            <option value="nonfiler">Non-Filer</option>
          </select>
        </div>
        {/* ... More input fields ... */}
         <div>
          <label>Annual Gross Salary</label>
          <input name="salary" type="number" value={input.salary} onChange={handleInputChange} />
        </div>
         <div>
          <label>Tax Deducted by Employer</label>
          <input name="whtSalary" type="number" value={input.whtSalary} onChange={handleInputChange} />
        </div>
        
      </div>
      <div style={{ flex: 1 }}>
        {renderResult()}
      </div>
    </div>
  );
}
